import React, { useEffect, useRef, useState } from "react";
import { gsap } from "gsap";
import { ScrollTrigger } from "gsap/ScrollTrigger";
import { AGENTS } from "../config/agents";

gsap.registerPlugin(ScrollTrigger);

const DashboardPage = ({ user, onLogout }) => {
  const [selectedAgent, setSelectedAgent] = useState(null);
  const [isDark, setIsDark] = useState(true);

  const heroRef = useRef(null);
  const cardsRef = useRef([]);
  const agentsRef = useRef([]);
  const chartRef = useRef(null);

  useEffect(() => {
    document.body.style.background = "#050508";

    gsap.fromTo(
      heroRef.current,
      {
        opacity: 0,
        y: 80,
        filter: "blur(20px)",
      },
      {
        opacity: 1,
        y: 0,
        filter: "blur(0px)",
        duration: 1.5,
        ease: "power4.out",
      }
    );

    gsap.fromTo(
      cardsRef.current,
      {
        opacity: 0,
        y: 60,
        scale: 0.92,
      },
      {
        opacity: 1,
        y: 0,
        scale: 1,
        stagger: 0.08,
        duration: 1.1,
        ease: "power3.out",
      }
    );

    gsap.fromTo(
      agentsRef.current,
      {
        opacity: 0,
        y: 100,
        rotateX: 20,
      },
      {
        opacity: 1,
        y: 0,
        rotateX: 0,
        stagger: 0.1,
        duration: 1.2,
        ease: "power4.out",
      }
    );

    gsap.to(".orb-1", {
      y: -40,
      duration: 5,
      repeat: -1,
      yoyo: true,
      ease: "power1.inOut",
    });

    gsap.to(".orb-2", {
      y: 40,
      duration: 6,
      repeat: -1,
      yoyo: true,
      ease: "power1.inOut",
    });

    gsap.to(".rotate-ring", {
      rotate: 360,
      duration: 20,
      repeat: -1,
      ease: "none",
    });
  }, []);

  const stats = [
    {
      title: "AI Operations",
      value: "2,847",
      icon: "⚡",
      color: "#A855F7",
      change: "+23%",
    },
    {
      title: "Revenue",
      value: "$284K",
      icon: "💰",
      color: "#00D4FF",
      change: "+18%",
    },
    {
      title: "Automation",
      value: "127",
      icon: "🤖",
      color: "#6EE7B7",
      change: "+31%",
    },
    {
      title: "Accuracy",
      value: "94.2%",
      icon: "📊",
      color: "#F472B6",
      change: "+6%",
    },
  ];

  const activities = [
    {
      agent: "Sales Agent",
      action:
        "Qualified 24 enterprise leads automatically from LinkedIn campaigns.",
      icon: "💼",
      color: "#6EE7B7",
      time: "2m ago",
    },
    {
      agent: "Support Agent",
      action:
        "Resolved 18 customer support tickets with 94% satisfaction rate.",
      icon: "🎧",
      color: "#818CF8",
      time: "15m ago",
    },
    {
      agent: "Marketing Agent",
      action:
        "Generated 12,400 impressions through AI campaign optimization.",
      icon: "📣",
      color: "#FB923C",
      time: "1h ago",
    },
    {
      agent: "Analytics Agent",
      action:
        "Predicted 23% revenue growth for next month using neural forecasting.",
      icon: "📈",
      color: "#38BDF8",
      time: "3h ago",
    },
  ];

  if (selectedAgent) {
    return (
      <div
        style={{
          minHeight: "100vh",
          background: "#050508",
          color: "white",
          display: "flex",
          alignItems: "center",
          justifyContent: "center",
          fontSize: 40,
          fontWeight: 800,
        }}
      >
        {selectedAgent.name}
      </div>
    );
  }

  return (
    <div
      style={{
        background: "#050508",
        minHeight: "100vh",
        color: "white",
        overflow: "hidden",
        position: "relative",
        fontFamily: "Inter, sans-serif",
      }}
    >
      {/* BACKGROUND */}
      <div className="grid-bg" />

      <div className="orb orb-1" />
      <div className="orb orb-2" />

      {/* SIDEBAR */}
      <aside className="sidebar">
        <div className="logo-box">⚡</div>

        <div className="sidebar-icons">
          {["🏠", "📊", "🤖", "⚡", "💬", "⚙️"].map((icon, i) => (
            <div key={i} className="side-icon">
              {icon}
            </div>
          ))}
        </div>
      </aside>

      {/* MAIN */}
      <main
        style={{
          marginLeft: 110,
          padding: "30px",
          position: "relative",
          zIndex: 2,
        }}
      >
        {/* NAVBAR */}
        <nav className="top-nav">
          <div>
            <h1 className="dashboard-title">Neural Command Center</h1>
            <p className="dashboard-subtitle">
              Welcome back, {user?.name || "User"}
            </p>
          </div>

          <div className="nav-actions">
            <button className="glass-btn">
              {isDark ? "🌙 Dark AI" : "☀️ Light"}
            </button>

            <button className="logout-btn" onClick={onLogout}>
              Logout
            </button>
          </div>
        </nav>

        {/* HERO SECTION */}
        <section ref={heroRef} className="hero-section">
          <div className="hero-left">
            <div className="hero-badge">
              ⚡ AI SYSTEMS OPERATIONAL
            </div>

            <h2 className="hero-heading">
              The Future Of <br />
              Autonomous Intelligence
            </h2>

            <p className="hero-text">
              Your AI workforce is actively generating leads,
              optimizing campaigns, automating workflows and
              predicting business growth in realtime.
            </p>

            <div className="hero-buttons">
              <button className="primary-btn">
                Launch AI System
              </button>

              <button className="secondary-btn">
                View Analytics
              </button>
            </div>
          </div>

          {/* AI CORE */}
          <div className="hero-right">
            <div className="ai-core">
              <div className="rotate-ring ring-1" />
              <div className="rotate-ring ring-2" />
              <div className="core-center" />
            </div>
          </div>
        </section>

        {/* STATS */}
        <section className="stats-grid">
          {stats.map((stat, i) => (
            <div
              key={i}
              ref={(el) => (cardsRef.current[i] = el)}
              className="stat-card"
            >
              <div className="stat-top">
                <div
                  className="stat-icon"
                  style={{
                    background: `${stat.color}20`,
                    boxShadow: `0 0 30px ${stat.color}55`,
                  }}
                >
                  {stat.icon}
                </div>

                <span
                  style={{
                    color: "#10B981",
                    fontWeight: 700,
                  }}
                >
                  {stat.change}
                </span>
              </div>

              <h3>{stat.title}</h3>

              <div
                className="stat-value"
                style={{
                  color: stat.color,
                }}
              >
                {stat.value}
              </div>
            </div>
          ))}
        </section>

        {/* ANALYTICS + ACTIVITY */}
        <section className="analytics-layout">
          {/* CHART */}
          <div className="chart-box" ref={chartRef}>
            <div className="section-header">
              <div>
                <h2>Revenue Intelligence</h2>
                <p>AI powered predictive analytics</p>
              </div>

              <div className="live-pill">
                <span className="live-dot" />
                LIVE
              </div>
            </div>

            <svg
              width="100%"
              height="240"
              viewBox="0 0 600 240"
            >
              <defs>
                <linearGradient
                  id="lineGrad"
                  x1="0"
                  y1="0"
                  x2="1"
                  y2="1"
                >
                  <stop
                    offset="0%"
                    stopColor="#A855F7"
                  />
                  <stop
                    offset="100%"
                    stopColor="#00D4FF"
                  />
                </linearGradient>

                <linearGradient
                  id="fillGrad"
                  x1="0"
                  y1="0"
                  x2="0"
                  y2="1"
                >
                  <stop
                    offset="0%"
                    stopColor="#A855F7"
                    stopOpacity="0.5"
                  />
                  <stop
                    offset="100%"
                    stopColor="#A855F7"
                    stopOpacity="0"
                  />
                </linearGradient>
              </defs>

              <path
                d="M0 180 C100 150 180 120 260 130 C340 140 400 80 480 70 C530 60 560 30 600 20"
                fill="none"
                stroke="url(#lineGrad)"
                strokeWidth="5"
                strokeLinecap="round"
              />

              <path
                d="M0 180 C100 150 180 120 260 130 C340 140 400 80 480 70 C530 60 560 30 600 20 L600 240 L0 240 Z"
                fill="url(#fillGrad)"
              />
            </svg>

            <div className="chart-stats">
              <div>
                <span>$284K</span>
                <p>Monthly Revenue</p>
              </div>

              <div>
                <span>94.2%</span>
                <p>Forecast Accuracy</p>
              </div>

              <div>
                <span>+23%</span>
                <p>Growth Rate</p>
              </div>
            </div>
          </div>

          {/* ACTIVITY */}
          <div className="activity-box">
            <div className="section-header">
              <div>
                <h2>Realtime Agent Activity</h2>
                <p>Autonomous operations feed</p>
              </div>
            </div>

            <div className="activity-list">
              {activities.map((item, i) => (
                <div key={i} className="activity-item">
                  <div
                    className="activity-icon"
                    style={{
                      background: `${item.color}15`,
                    }}
                  >
                    {item.icon}
                  </div>

                  <div className="activity-content">
                    <h4>{item.agent}</h4>
                    <p>{item.action}</p>
                  </div>

                  <span className="activity-time">
                    {item.time}
                  </span>
                </div>
              ))}
            </div>
          </div>
        </section>

        {/* AGENTS */}
        <section className="agents-section">
          <div className="section-header">
            <div>
              <h2>AI Workforce</h2>
              <p>Fully autonomous intelligent agents</p>
            </div>
          </div>

          <div className="agents-grid">
            {AGENTS.map((agent, i) => (
              <div
                key={agent.id}
                ref={(el) => (agentsRef.current[i] = el)}
                className="agent-card"
                onClick={() => setSelectedAgent(agent)}
              >
                <div
                  className="agent-glow"
                  style={{
                    background: `${agent.color}33`,
                  }}
                />

                <div
                  className="agent-icon"
                  style={{
                    background: `${agent.color}15`,
                    border: `1px solid ${agent.color}40`,
                  }}
                >
                  {agent.icon}
                </div>

                <h3>{agent.name}</h3>

                <p>{agent.tagline}</p>

                <button
                  style={{
                    background: `${agent.color}15`,
                    color: agent.color,
                    border: `1px solid ${agent.color}40`,
                  }}
                >
                  Launch Agent
                </button>
              </div>
            ))}
          </div>
        </section>

        {/* FOOTER */}
        <footer className="footer">
          <div className="footer-grid">
            <div>
              <h3>NexusAI</h3>
              <p>
                The world’s most advanced AI operating system.
              </p>
            </div>

            <div>
              <h4>Platform</h4>
              <span>Analytics</span>
              <span>Automation</span>
              <span>AI Agents</span>
            </div>

            <div>
              <h4>Resources</h4>
              <span>Documentation</span>
              <span>Security</span>
              <span>Status</span>
            </div>

            <div>
              <h4>Company</h4>
              <span>About</span>
              <span>Careers</span>
              <span>Contact</span>
            </div>
          </div>

          <div className="footer-bottom">
            © 2026 NexusAI Inc. All rights reserved.
          </div>
        </footer>
      </main>

      {/* CSS */}
      <style>{`
      
      *{
        box-sizing:border-box;
      }

      body{
        margin:0;
      }

      .grid-bg{
        position:fixed;
        inset:0;
        background-image:
        linear-gradient(rgba(255,255,255,0.03) 1px, transparent 1px),
        linear-gradient(90deg, rgba(255,255,255,0.03) 1px, transparent 1px);
        background-size:60px 60px;
        z-index:0;
      }

      .orb{
        position:fixed;
        border-radius:50%;
        filter:blur(120px);
        opacity:0.3;
        z-index:0;
      }

      .orb-1{
        width:500px;
        height:500px;
        background:#A855F7;
        top:-200px;
        left:-150px;
      }

      .orb-2{
        width:450px;
        height:450px;
        background:#00D4FF;
        right:-120px;
        bottom:-120px;
      }

      .sidebar{
        position:fixed;
        left:20px;
        top:20px;
        bottom:20px;
        width:70px;
        border-radius:30px;
        background:rgba(255,255,255,0.04);
        border:1px solid rgba(255,255,255,0.08);
        backdrop-filter:blur(30px);
        display:flex;
        flex-direction:column;
        align-items:center;
        z-index:20;
      }

      .logo-box{
        width:52px;
        height:52px;
        border-radius:18px;
        margin-top:18px;
        background:linear-gradient(135deg,#A855F7,#00D4FF);
        display:flex;
        align-items:center;
        justify-content:center;
        font-size:24px;
        box-shadow:0 0 40px rgba(168,85,247,0.5);
      }

      .sidebar-icons{
        margin-top:30px;
        display:flex;
        flex-direction:column;
        gap:16px;
      }

      .side-icon{
        width:50px;
        height:50px;
        border-radius:16px;
        display:flex;
        align-items:center;
        justify-content:center;
        background:rgba(255,255,255,0.04);
        border:1px solid rgba(255,255,255,0.05);
        cursor:pointer;
        transition:0.3s ease;
      }

      .side-icon:hover{
        transform:translateY(-4px) scale(1.05);
        background:rgba(168,85,247,0.15);
        box-shadow:0 0 30px rgba(168,85,247,0.25);
      }

      .top-nav{
        display:flex;
        justify-content:space-between;
        align-items:center;
        margin-bottom:40px;
      }

      .dashboard-title{
        font-size:52px;
        margin:0;
        line-height:1;
        font-weight:900;
        letter-spacing:-3px;
        background:linear-gradient(135deg,#fff,#A855F7,#00D4FF);
        -webkit-background-clip:text;
        -webkit-text-fill-color:transparent;
      }

      .dashboard-subtitle{
        color:rgba(255,255,255,0.5);
        margin-top:10px;
      }

      .nav-actions{
        display:flex;
        gap:16px;
      }

      .glass-btn,
      .logout-btn{
        height:50px;
        padding:0 24px;
        border-radius:18px;
        border:1px solid rgba(255,255,255,0.08);
        background:rgba(255,255,255,0.05);
        color:white;
        cursor:pointer;
        backdrop-filter:blur(20px);
      }

      .hero-section{
        min-height:540px;
        border-radius:40px;
        overflow:hidden;
        position:relative;
        margin-bottom:40px;

        background:
        linear-gradient(
        135deg,
        rgba(168,85,247,0.15),
        rgba(0,212,255,0.08)
        );

        border:1px solid rgba(255,255,255,0.08);

        display:grid;
        grid-template-columns:1fr 1fr;

        padding:60px;
      }

      .hero-left{
        position:relative;
        z-index:2;
      }

      .hero-badge{
        display:inline-flex;
        align-items:center;
        gap:10px;
        height:42px;
        padding:0 18px;
        border-radius:50px;
        background:rgba(168,85,247,0.15);
        border:1px solid rgba(168,85,247,0.25);
        margin-bottom:30px;
        font-size:13px;
        font-weight:700;
      }

      .hero-heading{
        font-size:74px;
        line-height:0.95;
        margin:0;
        font-weight:900;
        letter-spacing:-4px;
      }

      .hero-text{
        max-width:560px;
        margin-top:24px;
        color:rgba(255,255,255,0.6);
        line-height:1.8;
        font-size:17px;
      }

      .hero-buttons{
        display:flex;
        gap:18px;
        margin-top:40px;
      }

      .primary-btn{
        height:56px;
        padding:0 28px;
        border:none;
        border-radius:18px;
        background:linear-gradient(135deg,#A855F7,#7C3AED);
        color:white;
        font-weight:700;
        cursor:pointer;
        box-shadow:0 0 40px rgba(168,85,247,0.4);
      }

      .secondary-btn{
        height:56px;
        padding:0 28px;
        border-radius:18px;
        background:rgba(255,255,255,0.05);
        border:1px solid rgba(255,255,255,0.08);
        color:white;
        cursor:pointer;
      }

      .hero-right{
        position:relative;
        display:flex;
        align-items:center;
        justify-content:center;
      }

      .ai-core{
        width:360px;
        height:360px;
        position:relative;
      }

      .ring-1{
        position:absolute;
        inset:0;
        border-radius:50%;
        border:2px solid rgba(168,85,247,0.4);
        box-shadow:0 0 60px rgba(168,85,247,0.35);
      }

      .ring-2{
        position:absolute;
        inset:40px;
        border-radius:50%;
        border:2px solid rgba(0,212,255,0.4);
        box-shadow:0 0 60px rgba(0,212,255,0.35);
      }

      .core-center{
        position:absolute;
        inset:90px;
        border-radius:50%;

        background:
        radial-gradient(circle,#A855F7,#00D4FF,#050508);

        box-shadow:
        0 0 100px rgba(168,85,247,0.7),
        0 0 120px rgba(0,212,255,0.5);
      }

      .stats-grid{
        display:grid;
        grid-template-columns:repeat(4,1fr);
        gap:24px;
        margin-bottom:40px;
      }

      .stat-card{
        padding:28px;
        border-radius:30px;

        background:
        linear-gradient(
        135deg,
        rgba(255,255,255,0.05),
        rgba(255,255,255,0.02)
        );

        border:1px solid rgba(255,255,255,0.08);

        backdrop-filter:blur(30px);

        transition:0.4s ease;
      }

      .stat-card:hover{
        transform:translateY(-10px);
        box-shadow:0 20px 60px rgba(168,85,247,0.2);
      }

      .stat-top{
        display:flex;
        justify-content:space-between;
        margin-bottom:24px;
      }

      .stat-icon{
        width:64px;
        height:64px;
        border-radius:20px;
        display:flex;
        align-items:center;
        justify-content:center;
        font-size:28px;
      }

      .stat-card h3{
        color:rgba(255,255,255,0.6);
        margin-bottom:14px;
      }

      .stat-value{
        font-size:42px;
        font-weight:900;
      }

      .analytics-layout{
        display:grid;
        grid-template-columns:1.4fr 1fr;
        gap:24px;
        margin-bottom:50px;
      }

      .chart-box,
      .activity-box{
        padding:30px;
        border-radius:32px;

        background:
        linear-gradient(
        135deg,
        rgba(255,255,255,0.05),
        rgba(255,255,255,0.02)
        );

        border:1px solid rgba(255,255,255,0.08);

        backdrop-filter:blur(30px);
      }

      .section-header{
        display:flex;
        justify-content:space-between;
        align-items:center;
        margin-bottom:24px;
      }

      .section-header h2{
        margin:0;
        font-size:26px;
      }

      .section-header p{
        color:rgba(255,255,255,0.5);
        margin-top:8px;
      }

      .live-pill{
        display:flex;
        align-items:center;
        gap:8px;
        height:36px;
        padding:0 14px;
        border-radius:50px;
        background:rgba(16,185,129,0.15);
        border:1px solid rgba(16,185,129,0.3);
        font-size:12px;
        font-weight:700;
      }

      .live-dot{
        width:8px;
        height:8px;
        border-radius:50%;
        background:#10B981;
      }

      .chart-stats{
        display:flex;
        justify-content:space-between;
        margin-top:24px;
      }

      .chart-stats span{
        font-size:30px;
        font-weight:900;
      }

      .chart-stats p{
        color:rgba(255,255,255,0.5);
      }

      .activity-list{
        display:flex;
        flex-direction:column;
        gap:18px;
      }

      .activity-item{
        display:flex;
        align-items:center;
        gap:16px;
        padding:18px;
        border-radius:22px;
        background:rgba(255,255,255,0.03);
        transition:0.3s ease;
      }

      .activity-item:hover{
        transform:translateX(6px);
      }

      .activity-icon{
        width:58px;
        height:58px;
        border-radius:18px;
        display:flex;
        align-items:center;
        justify-content:center;
        font-size:28px;
      }

      .activity-content{
        flex:1;
      }

      .activity-content h4{
        margin:0;
      }

      .activity-content p{
        color:rgba(255,255,255,0.5);
        margin-top:6px;
        line-height:1.5;
      }

      .activity-time{
        color:rgba(255,255,255,0.4);
        font-size:12px;
      }

      .agents-section{
        margin-bottom:60px;
      }

      .agents-grid{
        display:grid;
        grid-template-columns:repeat(4,1fr);
        gap:24px;
      }

      .agent-card{
        position:relative;
        overflow:hidden;

        padding:30px;
        border-radius:32px;

        background:
        linear-gradient(
        135deg,
        rgba(255,255,255,0.05),
        rgba(255,255,255,0.02)
        );

        border:1px solid rgba(255,255,255,0.08);

        backdrop-filter:blur(30px);

        transition:0.4s ease;

        cursor:pointer;
      }

      .agent-card:hover{
        transform:
        translateY(-12px)
        rotateX(4deg);

        box-shadow:
        0 30px 80px rgba(168,85,247,0.25);
      }

      .agent-glow{
        position:absolute;
        width:220px;
        height:220px;
        border-radius:50%;
        filter:blur(80px);
        top:-60px;
        right:-60px;
        opacity:0.4;
      }

      .agent-icon{
        width:80px;
        height:80px;
        border-radius:24px;
        display:flex;
        align-items:center;
        justify-content:center;
        font-size:36px;
        margin-bottom:24px;
      }

      .agent-card h3{
        font-size:28px;
        margin-bottom:10px;
      }

      .agent-card p{
        color:rgba(255,255,255,0.55);
        line-height:1.7;
        margin-bottom:28px;
      }

      .agent-card button{
        height:48px;
        padding:0 22px;
        border-radius:16px;
        cursor:pointer;
        font-weight:700;
      }

      .footer{
        padding:50px 0;
        border-top:1px solid rgba(255,255,255,0.08);
      }

      .footer-grid{
        display:grid;
        grid-template-columns:2fr 1fr 1fr 1fr;
        gap:30px;
      }

      .footer h3{
        font-size:28px;
      }

      .footer p,
      .footer span{
        color:rgba(255,255,255,0.5);
        display:block;
        margin-top:12px;
      }

      .footer-bottom{
        margin-top:50px;
        padding-top:30px;
        border-top:1px solid rgba(255,255,255,0.08);
        color:rgba(255,255,255,0.4);
      }

      @media(max-width:1200px){

        .stats-grid,
        .agents-grid{
          grid-template-columns:repeat(2,1fr);
        }

        .analytics-layout{
          grid-template-columns:1fr;
        }

      }

      @media(max-width:900px){

        .hero-section{
          grid-template-columns:1fr;
          gap:40px;
        }

        .hero-heading{
          font-size:54px;
        }

      }

      @media(max-width:768px){

        main{
          margin-left:0 !important;
        }

        .sidebar{
          display:none;
        }

        .stats-grid,
        .agents-grid,
        .footer-grid{
          grid-template-columns:1fr;
        }

        .top-nav{
          flex-direction:column;
          align-items:flex-start;
          gap:20px;
        }

        .dashboard-title{
          font-size:42px;
        }

        .hero-heading{
          font-size:44px;
        }

        .hero-section{
          padding:30px;
        }

        .ai-core{
          width:280px;
          height:280px;
        }

      }

      `}</style>
    </div>
  );
};

export default DashboardPage;
